// Kiểm tra nếu user đã cung cấp email trực tiếp hay chỉ có tên
const params = $input.first().json.params || {};
const recipientRaw = params.recipient_name || params.recipient || '';
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// Nếu recipientRaw chứa @ → là email trực tiếp
const isDirectEmail = emailRegex.test(recipientRaw.trim());

return [{
  json: {
    ...($input.first().json),
    params: {
      ...params,
      is_direct_email: isDirectEmail,
      recipient_name: recipientRaw.trim(),
      direct_email: isDirectEmail ? recipientRaw.trim() : ''
    }
  }
}];

// Fuzzy match tên người nhận từ danh bạ
const allItems = $input.all();
const trigger = $node['Prepare Email Request'].json;
const params = trigger.params || {};
const recipientName = (params.recipient_name || '').toLowerCase().trim();

if (!recipientName) {
  return [{ json: { found: false, error: 'Thiếu tên người nhận', search_name: '' } }];
}

const contacts = allItems.filter(item => item.json && item.json.email);

// Priority match: exact name > biet_danh > partial name
let matched = null;

// 1) Exact match (case-insensitive)
matched = contacts.find(c => {
  const ten = (c.json.ten || '').toLowerCase().trim();
  return ten === recipientName;
});

// 2) Biet_danh match
if (!matched) {
  matched = contacts.find(c => {
    const aliases = (c.json.biet_danh || '').toLowerCase().split(',').map(s => s.trim());
    return aliases.some(a => a && (a === recipientName || a.includes(recipientName) || recipientName.includes(a)));
  });
}

// 3) Partial name match
if (!matched) {
  matched = contacts.find(c => {
    const ten = (c.json.ten || '').toLowerCase();
    return ten.includes(recipientName) || recipientName.includes(ten.split(' ').pop());
  });
}

// 4) Check for multiple matches
const allMatches = contacts.filter(c => {
  const ten = (c.json.ten || '').toLowerCase();
  const aliases = (c.json.biet_danh || '').toLowerCase();
  return ten.includes(recipientName) || aliases.includes(recipientName);
});

if (allMatches.length > 1) {
  const nameList = allMatches.map((c, i) => `${i+1}. ${c.json.ten} (${c.json.cong_ty || 'chưa có công ty'})`).join('\n');
  return [{
    json: {
      found: false,
      multiple_matches: true,
      error: `Có ${allMatches.length} liên hệ tên "${params.recipient_name}"`,
      match_list: nameList,
      search_name: params.recipient_name
    }
  }];
}

if (matched) {
  return [{
    json: {
      found: true,
      email: matched.json.email,
      name: matched.json.ten,
      company: matched.json.cong_ty || '',
      role: matched.json.vai_tro || '',
      group: matched.json.nhom || '',
      notes: matched.json.ghi_chu || ''
    }
  }];
}

// Not found — provide list of available contacts
const availableNames = contacts.slice(0, 10).map(c => c.json.ten).filter(Boolean).join(', ');
return [{
  json: {
    found: false,
    multiple_matches: false,
    error: `Không tìm thấy "${params.recipient_name}" trong danh bạ`,
    available_names: availableNames,
    search_name: params.recipient_name
  }
}];

// Hợp nhất thông tin liên hệ: từ lookup hoặc email trực tiếp
const trigger = $node['Prepare Email Request'].json;
const params = trigger.params || {};

let contactInfo;

if (params.is_direct_email) {
  // Email trực tiếp — không cần lookup
  contactInfo = {
    found: true,
    email: params.direct_email,
    name: params.recipient_name,
    company: '',
    role: '',
    group: ''
  };
} else {
  // Từ kết quả lookup
  contactInfo = $input.first().json;
}

return [{
  json: {
    contact: contactInfo,
    request: {
      body_prompt: params.email_body_prompt || params.raw_text || '',
      subject_hint: params.email_subject || '',
      chat_id: params.chat_id
    }
  }
}];

