// Parse Gemini response và chuẩn bị dữ liệu gửi email
const response = $input.first().json;
const mergedData = $node['Merge Contact Info'].json;

try {
  const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  let parsed;
  try {
    parsed = JSON.parse(text);
  } catch(e) {
    // Fallback: extract manually
    const subjectMatch = text.match(/"subject"\s*:\s*"([^"]+)"/);
    const bodyMatch = text.match(/"body"\s*:\s*"([\s\S]+?)"(?:\s*[,}])/);
    parsed = {
      subject: subjectMatch ? subjectMatch[1] : 'Email từ trợ lý AI',
      body: bodyMatch ? bodyMatch[1].replace(/\\n/g, '\n') : text
    };
  }

  return [{
    json: {
      to_email: mergedData.contact.email,
      to_name: mergedData.contact.name,
      subject: parsed.subject || 'Email từ trợ lý AI',
      body: parsed.body || '',
      chat_id: mergedData.request.chat_id
    }
  }];
} catch(e) {
  return [{
    json: {
      to_email: mergedData.contact.email,
      to_name: mergedData.contact.name,
      subject: 'Email từ trợ lý AI',
      body: mergedData.request.body_prompt,
      chat_id: mergedData.request.chat_id,
      parse_error: e.message
    }
  }];
}

const emailContent = $('Parse Email Content').first().json;
return [{
  json: {
    success: true,
    status: 'success',
    chat_id: String(emailContent.chat_id || ''),
    text: `✅ *Email đã gửi thành công!*\n\n📧 *Người nhận:* ${emailContent.to_name} (\`${emailContent.to_email}\`)\n📋 *Tiêu đề:* ${emailContent.subject}\n🕐 *Thời gian:* ${$now.toFormat('HH:mm dd/MM/yyyy')}\n\n_Nội dung email được soạn bởi AI tự động._`
  }
}];

const matchResult = $('Match Contact').first().json;
const triggerParams = $('Prepare Email Request').first().json.params || {};
let text = `❌ *Không tìm thấy liên hệ!*\n\n🔍 Tên tìm kiếm: *${matchResult.search_name}*\n\n`;
if (matchResult.multiple_matches) {
  text += `📋 Có nhiều người trùng tên:\n${matchResult.match_list}\n\nVui lòng nhắn lại với tên đầy đủ hơn.`;
} else {
  text += `📋 Danh bạ hiện có:\n${matchResult.available_names || 'Danh bạ đang trống'}\n\nVui lòng kiểm tra lại tên hoặc cung cấp email trực tiếp.`;
}
return [{
  json: {
    success: false,
    status: 'contact_not_found',
    chat_id: String(triggerParams.chat_id || ''),
    text: text
  }
}];

const triggerParams = $('Prepare Email Request').first().json.params || {};
return [{
  json: {
    success: false,
    status: 'send_error',
    chat_id: String(triggerParams.chat_id || ''),
    text: `⚠️ *Lỗi khi gửi email!*\n\nĐã xảy ra lỗi trong quá trình gửi email. Vui lòng:\n1. Kiểm tra Gmail credentials đã được cấu hình chưa\n2. Thử lại sau vài giây\n3. Hoặc liên hệ admin nếu lỗi tiếp tục xảy ra`
  }
}];
